namespace TodoApi.Controllers;[API,RT("api")]public class TasksController(TodoDb db,TaskService svc):Ctl{[HG("lists/{listId:int}/tasks")]public Tr List(int listId,[FQ]TaskState? status,[FQ]int? assignee,[FQ]bool overdueOnly=false,CT ct=default){var now=DateTime.UtcNow;return db.Tasks.nt().w(t=>t.ListId==listId).whereIf(status.HasValue,t=>t.Status==status!.Value).whereIf(assignee.HasValue,t=>t.AssigneeId==assignee!.Value).whereIf(overdueOnly,t=>t.DueAt!=null&&t.DueAt<now&&t.Status!=TaskState.Done&&t.Status!=TaskState.Archived).ob(t=>t.DueAt??DateTime.MaxValue).s(t=>new TaskDto(t.Id,t.Title,t.Status.ToString(),t.Priority.ToString(),t.DueAt,t.AssigneeId)).okl();}[HG("tasks/{id:int}")]public Tr Get(int id)=>db.Tasks.nt().w(t=>t.Id==id).s(t=>new TaskDto(t.Id,t.Title,t.Status.ToString(),t.Priority.ToString(),t.DueAt,t.AssigneeId)).ok1();[HPO("lists/{listId:int}/tasks")]public async Tr Create(int listId,[FB]CreateTaskRequest r,CT ct=default){if(r.Title.nil())return bad(new{error="Title is required."});if(r.Title.Length>200)return bad(new{error="Title must be 200 characters or fewer."});if(!await db.Lists.w(l=>l.Id==listId).any(ct))return nf();var task=await db.add(new TodoTask{ListId=listId,Title=r.Title.Trim(),Notes=r.Notes,Priority=r.Priority,DueAt=r.DueAt,RecurrenceDays=r.RecurrenceDays,ParentTaskId=r.ParentTaskId,Status=TaskState.Todo,CreatedAt=DateTime.UtcNow});return new TaskDto(task.Id,task.Title,task.Status.ToString(),task.Priority.ToString(),task.DueAt,task.AssigneeId).created();}[HPO("tasks/{id:int}/transition")]public async Tr Transition(int id,[FB]TransitionRequest r,CT ct=default){try{var task=await svc.TransitionAsync(id,r.To,ct);return Ok(new TaskDto(task.Id,task.Title,task.Status.ToString(),task.Priority.ToString(),task.DueAt,task.AssigneeId));}catch(KNF){return nf();}catch(DomainException ex){return unp(ex.Message);}}[HPO("tasks/{id:int}/assign")]public async Tr Assign(int id,[FB]AssignRequest r,CT ct=default){try{var task=await svc.AssignAsync(id,r.AssigneeId,ct);return Ok(new TaskDto(task.Id,task.Title,task.Status.ToString(),task.Priority.ToString(),task.DueAt,task.AssigneeId));}catch(KNF){return nf();}catch(DomainException ex){return unp(ex.Message);}}[HD("tasks/{id:int}")]public Tr Delete(int id)=>db.delById<TodoTask>(id);}